sys_script.script:
try {
  gs.info('Starting choice cleanup...');

  // Specific sys_ids of old role choices that need to be deleted
  var oldChoiceIds = [
    '50c4b67c93f37a908381f8bcdd03d6d8', // developer
    '90c4b67c93f37a908381f8bcdd03d6d8', // admin
    'd0c4b67c93f37a908381f8bcdd03d6d8', // business_analyst
    '14c4b67c93f37a908381f8bcdd03d6d8', // project_manager
    '54c4b67c93f37a908381f8bcdd03d6d8', // executive
    '94c4b67c93f37a908381f8bcdd03d6d8', // end_user
    'd4c4b67c93f37a908381f8bcdd03d6d8', // all
    'f7ddfe30933b7a908381f8bcdd03d605'  // all_roles
  ];

  var deletedCount = 0;
  for (var i = 0; i < oldChoiceIds.length; i++) {
    var gr = new GlideRecord('sys_choice');
    if (gr.get(oldChoiceIds[i])) {
      gs.info('Deleting choice record: ' + gr.getValue('value') + ' (' + gr.getValue('label') + ')');
      if (gr.deleteRecord()) {
        deletedCount++;
        gs.info('Successfully deleted choice: ' + gr.getValue('value'));
      }
    } else {
      gs.info('Choice record not found: ' + oldChoiceIds[i]);
    }
  }

  gs.info('Choice cleanup completed. Deleted ' + deletedCount + ' records.');

  // Update the trigger property to indicate completion
  var propGr = new GlideRecord('sys_properties');
  propGr.addQuery('name', 'x_snc_ai_learnin_4.cleanup_trigger');
  propGr.query();
  if (propGr.next()) {
    propGr.setValue('value', 'completed');
    propGr.setValue('description', 'Choice cleanup completed - ' + deletedCount + ' records deleted');
    propGr.update();
  }

} catch (error) {
  gs.error('Error in choice cleanup: ' + error.message);
}
